import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    /** Counts how many elements equal the given status string. */
    private int count(String[] arr, String val) {
        int c = 0;
        for (String s : arr) if (val.equals(s)) c++;
        return c;
    }

    /**
     * Asserts 3-way partition property:
     * all APPROVED before all DECLINED, all DECLINED before all FLAGGED.
     */
    private void assertPartitioned3Way(String[] arr) {
        // States: 0=in-APPROVED, 1=in-DECLINED, 2=in-FLAGGED
        int state = 0;
        for (String s : arr) {
            switch (s) {
                case "APPROVED":
                    if (state > 0) fail("Found APPROVED after DECLINED or FLAGGED: " + java.util.Arrays.toString(arr));
                    break;
                case "DECLINED":
                    if (state > 1) fail("Found DECLINED after FLAGGED: " + java.util.Arrays.toString(arr));
                    state = Math.max(state, 1);
                    break;
                case "FLAGGED":
                    state = 2;
                    break;
                default:
                    fail("Unexpected status value: " + s);
            }
        }
    }

    @Test
    void mixed() {
        String[] s = {"FLAGGED", "APPROVED", "DECLINED", "APPROVED", "FLAGGED"};
        new Solution().partitionStatuses(s);
        assertEquals(2, count(s, "APPROVED"));
        assertEquals(1, count(s, "DECLINED"));
        assertEquals(2, count(s, "FLAGGED"));
        assertPartitioned3Way(s);
    }

    @Test
    void allApproved() {
        String[] s = {"APPROVED", "APPROVED", "APPROVED"};
        new Solution().partitionStatuses(s);
        assertEquals(3, count(s, "APPROVED"));
        assertEquals(0, count(s, "DECLINED"));
        assertEquals(0, count(s, "FLAGGED"));
        assertPartitioned3Way(s);
    }

    @Test
    void allFlagged() {
        String[] s = {"FLAGGED", "FLAGGED", "FLAGGED"};
        new Solution().partitionStatuses(s);
        assertEquals(0, count(s, "APPROVED"));
        assertEquals(0, count(s, "DECLINED"));
        assertEquals(3, count(s, "FLAGGED"));
        assertPartitioned3Way(s);
    }

    @Test
    void noFlagged() {
        String[] s = {"DECLINED", "APPROVED", "APPROVED", "DECLINED"};
        new Solution().partitionStatuses(s);
        assertEquals(2, count(s, "APPROVED"));
        assertEquals(2, count(s, "DECLINED"));
        assertEquals(0, count(s, "FLAGGED"));
        assertPartitioned3Way(s);
    }

    @Test
    void singleElement() {
        String[] s = {"DECLINED"};
        new Solution().partitionStatuses(s);
        assertEquals(0, count(s, "APPROVED"));
        assertEquals(1, count(s, "DECLINED"));
        assertEquals(0, count(s, "FLAGGED"));
        assertPartitioned3Way(s);
    }

    @Test
    void alreadyPartitioned() {
        String[] s = {"APPROVED", "APPROVED", "DECLINED", "FLAGGED", "FLAGGED"};
        new Solution().partitionStatuses(s);
        assertEquals(2, count(s, "APPROVED"));
        assertEquals(1, count(s, "DECLINED"));
        assertEquals(2, count(s, "FLAGGED"));
        assertPartitioned3Way(s);
    }

    @Test
    void reverseOrder() {
        // adversarial: all FLAGGED, then DECLINED, then APPROVED
        String[] s = {"FLAGGED", "FLAGGED", "DECLINED", "DECLINED", "APPROVED"};
        new Solution().partitionStatuses(s);
        assertEquals(1, count(s, "APPROVED"));
        assertEquals(2, count(s, "DECLINED"));
        assertEquals(2, count(s, "FLAGGED"));
        assertPartitioned3Way(s);
    }
}
